package com.ichi2.anki

import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.anki.cardviewer.ViewerCommand
import org.junit.Test
import org.junit.runner.RunWith
import org.robolectric.annotation.Config
import kotlin.test.assertEquals
import kotlin.test.assertFalse
import kotlin.test.assertTrue

@RunWith(AndroidJUnit4::class)
@Config(qualifiers = "en")
class ToggleAutoAdvanceTest : RobolectricTest() {

    @Test
    fun testToggleAutoAdvanceCommand() {
        // Verify that TOGGLE_AUTO_ADVANCE command exists
        val command = ViewerCommand.TOGGLE_AUTO_ADVANCE
        assertEquals(R.string.toggle_auto_advance, command.resourceId)
    }

    @Test
    fun testToggleAutoAdvanceWithDisabledSetting() {
        val reviewer = startReviewer()
        // Verify that automaticAnswer exists
        val automaticAnswer = reviewer.automaticAnswer

        // If auto advance is not enabled in settings, toggle should do nothing
        if (!automaticAnswer.isEnabled()) {
            val wasDisabled = automaticAnswer.isDisabled
            reviewer.executeCommand(ViewerCommand.TOGGLE_AUTO_ADVANCE)
            // State should not change if auto advance is not enabled in settings
            assertEquals(wasDisabled, automaticAnswer.isDisabled)
        }
    }

    @Test
    fun testToggleAutoAdvanceEnabledToDisabled() {
        val reviewer = startReviewer()
        val automaticAnswer = reviewer.automaticAnswer

        // Skip test if auto advance is not enabled in settings
        if (!automaticAnswer.isEnabled()) {
            return
        }

        // Initially should be enabled (not disabled)
        assertFalse(automaticAnswer.isDisabled, "AutomaticAnswer should start enabled")

        // Toggle to disable
        reviewer.executeCommand(ViewerCommand.TOGGLE_AUTO_ADVANCE)
        assertTrue(automaticAnswer.isDisabled, "AutomaticAnswer should be disabled after toggle")

        // Toggle back to enable
        reviewer.executeCommand(ViewerCommand.TOGGLE_AUTO_ADVANCE)
        assertFalse(automaticAnswer.isDisabled, "AutomaticAnswer should be enabled after second toggle")
    }

    private fun startReviewer(): Reviewer {
        val reviewer = Reviewer()
        startActivityNormallyOpenCollectionWithIntent(reviewer, android.content.Intent())
        return reviewer
    }
}
